428	\section{Stein finiteness of global sections}
429	\label{sec:module_finite_globalSections_iter044}
430	
431	The geometric input for the wholespace Hom-finiteness carrier is Stein's theorem: on a proper integral scheme over a field, global sections are finite-dimensional.
432	
433	\begin{theorem}\mathlibok
434	[Module-finiteness of the top-section map of a universally closed morphism]
435	  \label{thm:finite_appTop_of_universallyClosed}
436	  \lean{AlgebraicGeometry.finite_appTop_of_universallyClosed}
437	
438	  Let \(K\) be a commutative ring and \(X\) an integral scheme equipped with a
439	  universally closed, locally-of-finite-type morphism \(f : X \to \Spec K\).
440	  Then the ring map on top sections \(f^\sharp_{\top}\) is module-finite.
441	
442	  \textit{Provided by Mathlib.}
443	\end{theorem}
444	
445	\begin{theorem}\leanok
446	[Stein finiteness of global sections]
447	  \label{thm:Scheme_module_finite_globalSections_of_isProper}
448	  \lean{AlgebraicGeometry.Scheme.module_finite_globalSections_of_isProper}
449	  \uses{thm:finite_appTop_of_universallyClosed, def:Scheme_kToSection}
450	
451	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then \(\Gamma(C, \mathcal O_C)\) is finite-dimensional over \(k\).
452	\end{theorem}
453	
454	\begin{proof}
455	  
456	  \leanok
457	  Apply the theorem that for an integral scheme with a universally closed, locally finite-type morphism to \(\Spec k\), the structure-morphism ring map on global sections is module-finite. Transfer the base ring from \(\Gamma(\Spec k, \top)\) to \(k\) along the canonical ring isomorphism.
458	\end{proof}
459	
460	\section{Global-sections evaluation isomorphism}
461	\label{sec:gammaObj_linearEquiv_top}
462	
463	To bridge from global sections (a concrete \(k\)-module) to the abstract Hom-from-constant-sheaf form, we lift the natural isomorphism between global sections and evaluation at the terminal object to a \(k\)-linear equivalence.
464	
465	\begin{theorem}\leanok
466	[Global-sections-to-top linear equivalence]
467	  \label{thm:Scheme_SheafGammaObj_linearEquiv_top}
468	  \lean{AlgebraicGeometry.Scheme.SheafGammaObj_linearEquiv_top}
469	  
470	  Let \(k\) be a field, \(X\) a topological space, and \(F\) a sheaf of \(k\)-modules on \(X\). Then there is a \(k\)-linear equivalence between the global-sections object of \(F\) and the evaluation of \(F\) at the top open \(\top\).
471	\end{theorem}
472	
473	\begin{theorem}\leanok
474	[Finite-dimensionality on global-sections object]
475	  \label{thm:Scheme_module_finite_gammaObj_of_isProper}
476	  \lean{AlgebraicGeometry.Scheme.module_finite_gammaObj_of_isProper}
477	  \uses{thm:Scheme_module_finite_globalSections_of_isProper, thm:Scheme_SheafGammaObj_linearEquiv_top}
478	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then the global-sections object of the \(k\)-module-valued structure sheaf is finite-dimensional over \(k\).
479	\end{theorem}
480	
481	\begin{proof}
482	  
483	  \leanok
484	  Combine Theorem~REF with the linear equivalence of Theorem~REF, transporting finite-dimensionality across the symmetric form.
485	\end{proof}
486	
487	\section{Producer instance for wholespace Hom-finiteness}
488	\label{sec:IsHModuleHomFinite_producer}
489	
490	We now assemble the chain: constant-sheaf/global-sections adjunction, Hom-from-\(k\) evaluation, and Stein finiteness, to produce the wholespace \(H^0\) Hom-finiteness instance.
491	
492	\begin{lemma}\leanok
493	[Linear lifting of adjoint functors]
494	  \label{lemma:Adjunction_left_adjoint_linear}
495	  \lean{CategoryTheory.Adjunction.left_adjoint_linear}
496	  Let \(F \dashv G\) be an adjunction between \(R\)-linear preadditive categories. If \(G\) is \(R\)-linear, then \(F\) is \(R\)-linear.
497	\end{lemma}
498	
499	\begin{lemma}\leanok
500	[Right-adjoint version]
501	  \label{lemma:Adjunction_right_adjoint_linear}
502	  \lean{CategoryTheory.Adjunction.right_adjoint_linear}
503	  Dual of Lemma~REF: if \(F\) is \(R\)-linear, then \(G\) is \(R\)-linear.
504	\end{lemma}
505	
506	\begin{theorem}\leanok
507	[Linear hom-equivalence from an adjunction]
508	  \label{def:Adjunction_homLinearEquiv}
509	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
510	  
511	  Let \(F \dashv G\) be an adjunction between \(R\)-linear preadditive categories with \(G\) additive and \(R\)-linear. Then for all objects \(X\) and \(Y\), the additive equivalence of the adjunction upgrades to an \(R\)-linear equivalence between \(\Hom(FX, Y)\) and \(\Hom(X, GY)\).
512	\end{theorem}
513	
514	\begin{theorem}\leanok
515	[Constant-sheaf / global-sections linear equivalence]
516	  \label{def:Scheme_constantSheafGammaHom_linearEquiv}
517	  \lean{AlgebraicGeometry.Scheme.constantSheafGammaHom_linearEquiv}
518	  \uses{lemma:Adjunction_left_adjoint_linear, lemma:Adjunction_right_adjoint_linear, def:Adjunction_homLinearEquiv}
519	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules, and \(F\) a sheaf of \(k\)-modules. For any \(k\)-module \(X\), there is a \(k\)-linear equivalence between morphisms from the constant sheaf at \(X\) to \(F\), and \(k\)-linear maps from \(X\) to the global sections of \(F\).
520	\end{theorem}
521	
522	\begin{theorem}\leanok
523	[Hom-from-\(k\) evaluation]
524	  \label{def:Scheme_homFromOne_linearEquiv}
525	  \lean{AlgebraicGeometry.Scheme.homFromOne_linearEquiv}
526	  For any field \(k\) and \(k\)-module \(M\), there is a canonical \(k\)-linear equivalence between \(\Hom_k(k, M)\) and \(M\) given by evaluation at \(1\).
527	\end{theorem}
528	
529	\begin{theorem}\leanok
530	[Producer instance for wholespace Hom-finiteness]
531	  \label{inst:Scheme_instIsHModuleHomFinite_toModuleKSheaf}
532	  \lean{AlgebraicGeometry.Scheme.instIsHModuleHomFinite_toModuleKSheaf}
533	  \uses{thm:Scheme_module_finite_gammaObj_of_isProper, def:Scheme_constantSheafGammaHom_linearEquiv, def:Scheme_homFromOne_linearEquiv, thm:Scheme_IsHModuleHomFinite}
534	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then wholespace \(H^0\) Hom-finiteness holds for the \(k\)-module-valued structure sheaf of \(C\).
535	\end{theorem}
536	
537	\begin{proof}
538	  
539	  \leanok
540	  Compose the constant-sheaf/global-sections linear equivalence (specialised to \(X = k\)) with the Hom-from-\(k\) evaluation to obtain a linear equivalence between the global Hom group and the global-sections object. Theorem~REF provides finite-dimensionality on the latter; transport across the symmetric form of the equivalence.
541	\end{proof}
542	
543	\begin{remark}
544	  Once this producer instance is registered, the consumer of Theorem~REF fires automatically, closing \(H^0_{\Module}(\mathcal O_C)\) finite-dimensionality for proper integral curves.
545	\end{remark}
546	
547	\section{Foundational parameterised \v{C}ech infrastructure}
548	\label{sec:moduleK_cech_parameterised}
549	
550	We generalise the \v{C}ech carriers from the structure sheaf to an arbitrary sheaf of \(k\)-modules, laying the scaffolding for the \v{C}ech-vs-derived comparison theorem.
551	
552	\begin{definition}\leanok
553	[Parameterised \v{C}ech complex]
554	  \label{def:Scheme_cechCochain}
555	  \lean{AlgebraicGeometry.Scheme.cechCochain}
556	  
557	  Let \(C\) be a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules on \(C\), and \(\mathcal U\) an indexed family of opens. Define the \v{C}ech cochain complex of \(F\) with respect to \(\mathcal U\) to be the standard \v{C}ech complex applied to the underlying presheaf of \(F\). This is a cochain complex valued in \(k\)-modules.
558	\end{definition}
559	
560	\begin{definition}\leanok
561	[Parameterised \v{C}ech cohomology]
562	  \label{def:Scheme_cechCohomology}
563	  \lean{AlgebraicGeometry.Scheme.cechCohomology}
564	  \uses{def:Scheme_cechCochain}
565	  With \((C, F, \mathcal U)\) as in Definition~REF, define the \(n\)-th \v{C}ech cohomology to be the \(n\)-th homology of the \v{C}ech cochain complex.
566	\end{definition}
567	
568	\begin{theorem}\leanok
569	[\v{C}ech complex bridge to structure-sheaf specialisation]
570	  \label{thm:Scheme_cechCochain_OC_eq}
571	  \lean{AlgebraicGeometry.Scheme.cechCochain_OC_eq}
572	  \uses{def:Scheme_cechCochain_OC, def:Scheme_cechCochain, def:Scheme_toModuleKSheaf}
573	  The structure-sheaf \v{C}ech complex equals the parameterised \v{C}ech complex at \(F = \mathcal O_C\).
574	\end{theorem}
575	
576	\begin{theorem}\leanok
577	[\v{C}ech cohomology bridge to structure-sheaf specialisation]
578	  \label{thm:Scheme_cechCohomology_OC_eq}
579	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC_eq}
580	  \uses{def:Scheme_cechCohomology_OC, def:Scheme_cechCohomology, def:Scheme_toModuleKSheaf}
581	  The structure-sheaf \v{C}ech cohomology equals the parameterised \v{C}ech cohomology at \(F = \mathcal O_C\).
582	\end{theorem}
583	
584	\begin{remark}
585	  These generalisations do not construct any comparison map between \v{C}ech and derived cohomology, nor do they prove vanishing. The substantive work is queued for subsequent iterations.
586	\end{remark}
587	
588	\section{\v{C}ech-side acyclicity carrier}
589	\label{sec:moduleK_cech_acyclic_cover}
590	
591	We introduce a carrier predicate capturing positive-degree vanishing of \v{C}ech cohomology, together with a consumer that transports this vanishing to derived cohomology once a comparison isomorphism is available.
592	
593	\begin{definition}\leanok
594	[\v{C}ech acyclicity carrier predicate]
595	  \label{def:Scheme_IsCechAcyclicCover}
596	  \lean{AlgebraicGeometry.Scheme.IsCechAcyclicCover}
597	  
598	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules on \(C\), and \(\mathcal U\) an indexed family of opens. The cover \(\mathcal U\) is \v{C}ech-acyclic for \(F\) if the \v{C}ech cohomology vanishes in positive degrees: for every \(n \ge 1\), the \(n\)-th \v{C}ech cohomology group is a subsingleton.
599	\end{definition}
600	
601	\begin{theorem}\leanok
602	[Derived vanishing from \v{C}ech acyclicity]
603	  \label{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover}
604	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover}
605	  
606	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules, and \(\mathcal U\) a \v{C}ech-acyclic cover for \(F\). Suppose there is a \(k\)-linear comparison isomorphism between \v{C}ech cohomology and derived cohomology of the cover supremum for every degree. Then for every \(n \ge 1\), the derived cohomology of the cover supremum is a subsingleton.
607	\end{theorem}
608	
609	\begin{proof}
610	  
611	  \leanok
612	  Transport the subsingleton structure along the symmetric form of the comparison isomorphism.
613	\end{proof}
614	
615	\begin{theorem}\leanok
616	[Curve specialisation]
617	  \label{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover_curve}
618	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover_curve}
619	  
620	  Curve specialisation of Theorem~REF at \(F = \mathcal O_C\).
621	\end{theorem}
622	
623	\section{Use in the project}
624	
625	The composition of the four typeclass instances of Sections~REF--REF, Definition~REF, and Definition~REF delivers Phase~A step~5 in full and bridges to Phase~A step~6:
626	
627	\begin{itemize}
628	  \item For \(C\) a scheme over \(\Spec k\), the \(k\)-module-valued cohomology \(H^n_{\Module}(\mathcal O_C)\) is well-defined and automatically carries a \(k\)-module structure, so \(\dim_k H^n_{\Module}(\mathcal O_C)\) is well-defined.
629	  \item Forgetting the \(k\)-module structure recovers the abelian-group cohomology of Chapter~REF, so the two theories commute on the underlying type level.
630	  \item Phase~A step~6 (Serre finiteness) remains the deep work to come, but is now expressible inside the standard \(k\)-module API: the statement becomes the finite-dimensionality predicate on \(H^n_{\Module}(F)\).
631	\end{itemize}
